import os, re, json, csv
from pathlib import Path
from collections import defaultdict, deque, Counter
base=Path('/app')
prod_re=re.compile(r'P_(\d+)')
store_re=re.compile(r'S_(\d+)')
pr_re=re.compile(r'PR_(\d+)')

def prod_key(p): return int(p.split('_')[1])
def store_key(s): return int(s.split('_')[1])
def pr_key(pr): return int(pr.split('_')[1])

def parse_order_file(path):
    name=path.name
    m=re.match(r'day_(\d+)_(S_\d+)_', name); day=int(m.group(1)); store=m.group(2)
    text=path.read_text()
    items={}
    if path.suffix=='.json':
        data=json.loads(text); store=data['store_id']; day=int(data['date'].split('_')[1])
        items={it['prod_id']: int(it['qty']) for it in data['items']}
    elif path.suffix=='.csv':
        for row in csv.DictReader(text.splitlines(), delimiter=';'):
            items[row['PRODUCT']]=int(row['QUANTITY'])
    elif 'key-value' in name:
        for line in text.splitlines():
            m=re.search(r'RECEIVER:\s*(S_\d+)\s*\|\s*ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
            if m:
                store=m.group(1); items[m.group(2)]=int(m.group(3))
    else:
        for line in text.splitlines():
            m=re.search(r'deliver\s+(\d+)\s+units of product\s+(P_\d+).*Store\s+(S_\d+)', line)
            if m:
                items[m.group(2)]=int(m.group(1)); store=m.group(3)
    return day,store,items

def parse_supplier_file(path):
    name=path.name; text=path.read_text()
    m=re.match(r'day_(\d+)_(PR_\d+)_', name); day=int(m.group(1)); pr=m.group(2)
    items={}
    if path.suffix=='.json':
        data=json.loads(text); pr=data['supplier_id']; day=int(data['date'].split('_')[1])
        items={it['prod_id']: int(it['delivered_qty']) for it in data['items']}
    elif path.suffix=='.csv':
        for row in csv.DictReader(text.splitlines(), delimiter=';'):
            items[row['PRODUCT']]=int(row['DELIVERED_QTY'])
    elif 'key-value' in name:
        m2=re.search(r'SUPPLIER:\s*(PR_\d+)\s*\|\s*DAY:\s*(\d+)', text)
        if m2: pr=m2.group(1); day=int(m2.group(2))
        for line in text.splitlines():
            m=re.search(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)', line)
            if m: items[m.group(1)]=int(m.group(2))
    else:
        for line in text.splitlines():
            m=re.search(r'Supplier\s+(PR_\d+)\s+delivered\s+(\d+)\s+units of product\s+(P_\d+).*Day_(\d+)', line)
            if m:
                pr=m.group(1); items[m.group(3)]=int(m.group(2)); day=int(m.group(4))
    return day,pr,items

def parse_receipt_kv(path):
    d={}
    for line in path.read_text().splitlines():
        if ':' in line:
            k,v=line.split(':',1); d[k.strip()]=v.strip()
    return d

orders=defaultdict(dict)
for p in (base/'raw_orders').iterdir():
    day,store,items=parse_order_file(p)
    orders[day][store]=items
sup=defaultdict(dict)
for p in (base/'raw_supplier_receipts').iterdir():
    day,pr,items=parse_supplier_file(p)
    sup[day][pr]=items
wr_seq=defaultdict(list)
for p in (base/'raw_wholesaler_receipts').iterdir():
    d=parse_receipt_kv(p); day=int(d['DAY']); pr=d['SUPPLIER_ID']; seq=int(d['DAILY_SEQUENCE_NO'])
    wr_seq[day].append((seq,pr))
for day in wr_seq: wr_seq[day].sort()
store_seq=defaultdict(list)
store_total={}
for p in (base/'raw_wholesaler_store_receipts').iterdir():
    d=parse_receipt_kv(p); day=int(d['DAY']); store=d['STORE_ID']; seq=int(d['DAILY_SEQUENCE_NO']); total=int(d['TOTAL_DELIVERED_UNITS'])
    store_seq[day].append((seq,store)); store_total[(day,store)]=total
for day in store_seq: store_seq[day].sort()
print('days',len(orders),len(sup),len(wr_seq),len(store_seq),'orders day1 stores',len(orders[1]),'sup day1',len(sup[1]))
print('max PR', max(pr_key(pr) for day in sup for pr in sup[day]), 'products', len({p for day in orders for st in orders[day].values() for p in st}))
# validate order sums equal sales reported demand aggregate per product/store/day
sales_agg=defaultdict(Counter)
with open(base/'sales_log.csv') as f:
    for r in csv.DictReader(f):
        sales_agg[(int(r['Day']), r['Store_ID'])][r['Product_ID']] += int(r['Reported_Demand'])
mis=0
for day, bys in orders.items():
    for st,it in bys.items():
        if Counter(it)!=sales_agg[(day,st)]:
            mis+=1
            if mis<5: print('order mismatch',day,st, sum(it.values()), sum(sales_agg[(day,st)].values()), Counter(it)-sales_agg[(day,st)], sales_agg[(day,st)]-Counter(it))
print('order mismatches',mis)
# simulate fulfillment, validate store total receipts
wh={p:deque() for p in [f'P_{i}' for i in range(1,31)]}
store_inv={st:{p:deque() for p in [f'P_{i}' for i in range(1,31)]} for st in [f'S_{i}' for i in range(1,11)]}
# We'll simulate sales using sold_quantity depletion; before replenish daily.
sold_mismatch=[]
receipt_mismatch=[]
alloc_by_day_store=defaultdict(lambda: defaultdict(list))
# load sales rows grouped by day store in file order
sales_rows=defaultdict(lambda: defaultdict(list))
with open(base/'sales_log.csv') as f:
    for r in csv.DictReader(f): sales_rows[int(r['Day'])][r['Store_ID']].append(r)
for day in range(1,366):
    # sales before replenish
    for store in sorted(sales_rows[day], key=store_key):
        for idx,r in enumerate(sales_rows[day][store]):
            p=r['Product_ID']; dem=int(r['Reported_Demand']); sold=int(r['Sold_Quantity'])
            avail=sum(q for _,q in store_inv[store][p])
            exp=min(dem, avail)
            if exp!=sold:
                sold_mismatch.append((day,store,idx,p,dem,sold,avail,exp, list(store_inv[store][p])[:3]))
                # still deplete actual sold
            need=sold
            q=store_inv[store][p]
            while need>0 and q:
                pr,qty=q[0]
                take=min(need, qty)
                qty-=take; need-=take
                if qty: q[0]=(pr,qty)
                else: q.popleft()
            if need:
                # sold more than inv
                pass
    # supplier into wholesaler
    for seq,pr in wr_seq[day]:
        for p,qty in sorted(sup[day][pr].items(), key=lambda kv: prod_key(kv[0])):
            wh[p].append((pr,qty))
    # fulfill stores in sequence; product order ascending
    for seq,store in store_seq[day]:
        total=0
        for p,req in sorted(orders[day][store].items(), key=lambda kv: prod_key(kv[0])):
            need=req; delivered=[]
            q=wh[p]
            while need>0 and q:
                pr,qty=q[0]
                take=min(need, qty)
                delivered.append((pr,take)); store_inv[store][p].append((pr,take))
                qty-=take; need-=take; total+=take
                if qty: q[0]=(pr,qty)
                else: q.popleft()
            if delivered: alloc_by_day_store[(day,store)][p].extend(delivered)
        if total!=store_total[(day,store)]:
            receipt_mismatch.append((day,store,total,store_total[(day,store)]))
print('receipt mismatches',len(receipt_mismatch), receipt_mismatch[:10])
print('sold mismatches',len(sold_mismatch))
print('first sold mismatches',sold_mismatch[:10])
# aggregate mismatches types
if sold_mismatch:
    print('mismatch days', Counter(d for d,*_ in sold_mismatch).most_common(10))
PY

